from sklearn.metrics.pairwise import cosine_similarity

def analyze_organization_relationships(context):
    # Extract relevant parts of the context
    organization_a = context.split('Organization A: ')[1].split('Organization B:')[0]

    # Analyze the relationships
    similar_organizations = []
    for i, org_b in enumerate(organization_a.split(', ')):
        if org_b == 'Digital Network Associates Private Limited':
