        for j, org_a in enumerate(org_b.split(',')):
            if org_a != 'Digital Network Associates Private Limited':
                similar_organizations.append((org_a, org_b))

    # Calculate cosine similarity between each pair of organizations
    similarities = [cosine_similarity([org_a], [org_b])[0][0] for org_a, org_b in similar_organizations]

    return max(similarities)

